INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-814ced5a-moex-00126', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「以大自然解釋院子四周的生物起落生死，似乎太過遼闊而弘遠，但那確實又是自開自落的生命定律。 在鄉野間，生命看似荒蠻，卻沉默、堅定，以它自己的節奏持續循環。山深不知處的鳥雀啄食了遠方 的木瓜，偶然飛駐這庭裡，啁啾啁啾，遺下了籽，土壤也許正好雨過，一切恰好，因此亭亭發芽。」 根據上文，下列選項何者最接近文意？', '["在大自然之中，萬物生命奧妙難解，有其循環與規律", "在大自然之中，愈是蠻荒的環境，更加容易繁衍生命", "生物各有生長所需的環境，如同院子中的鳥雀與木瓜", "生物必須在充沛的土壤與雨水中，才能繁衍滋長生命"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00127', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「孤單也許囿限囚禁我的靈魂，卻又為我開拓浩瀚壯闊的地界。『我是多麼孤單！』當我這般嘆息，林 中的鳥兒卻回答說：『你忽略了孤單的奧妙。』綺麗的天空飄著海水漂染藍藍的雲彩，因為孤單，大 自然的美占據心靈的空間。」 根據上文，「孤單的奧妙」指的是：', '["失去囚禁的靈魂", "打開心靈的感官", "獲得自然的同情", "接受生活的現實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00128', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '承上題，下列選項何者與作者的感受最接近？', '["念天地之悠悠，獨愴然而涕下", "獨在異鄉為異客，每逢佳節倍思親", "獨有宦遊人，偏驚物候新，雲霞出海曙，梅柳渡江春", "問余何事栖碧山，笑而不答心自閒。桃花流水杳然去，別有天地非人間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00129', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「臺灣其實是不折不扣的『海洋之島』！在五至七百萬年前，就如從貝殼中誕生的維娜斯，在菲律賓 海板塊和歐亞大陸板塊的推擠之下，從深邃的太平洋海底冉冉升起。新生的臺灣，當然是光禿禿的一 片，但是海風帶來了陸上的植物，海流帶來了海中的魚蝦，海退，讓大陸上的生物得以由陸橋進入臺 灣；海進，讓隔絕在臺灣的生物得以演進成新種，以致在今天這小小三萬六千平方公里的地方，約有 四千多種維管束植物、一千四百種苔蘚、四千八百種真菌、一萬八千種昆蟲，部分甚至占到全球同類 物種的十分之一以上，相對於臺灣陸地面積所占有全世界大陸面積的渺小，約千分之零點二四而已。」 根據上文，下列選項何者最符合臺灣有如此豐富生物資源的原因？', '["菲律賓海板塊和歐亞大陸板塊的不斷推擠，讓土地肥沃", "政府政策得宜，加強復育工作，各種生物適應能力強大", "海洋環境長期變化歷程，帶來新物種，也營造特有的演化環境", "環保觀念深植人心，讓魚蝦、昆蟲的環境優渥，食物供應不絕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00130', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「近來，隨著對快時尚產業的了解以及全球暖化的加劇，外界也開始鼓勵『道德時尚』（ethicalfashion）： 旨在對人類、動物和地球降低負面影響的時尚。這也是敦促生產商檢視生產材料和勞動環境之外，呼 籲消費者也需為此負上一定責任——不成為快時尚產業的主要推動力。因此，人們也開始關心如何讓 衣服變得『永續』，例如有相關網站提供延長衣服壽命的技巧，以降低衣服在全球的碳足跡。當然， 再次循環使用的二手衣物也是緩解方式之一，但不應該建立在快速消費、快速淘汰的前提之下。」 根據上文，下列選項何者正確？', '["延長衣服壽命可以降低碳足跡，屬於道德時尚的一環", "道德時尚關注人類福祉，多少會加重對動物的負面影響", "再次循環使用二手衣物可以快速淘汰衣服，以減緩全球暖化", "道德時尚可以改善勞動環境，也可以降低消費者的責任和負擔"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00131', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「疾病是人類共同的、普遍的、恆久的生物性經驗之一，不僅是人類生活與生命中無法割捨的一部分， 其存滅與盛衰，更與人類社會的發展、文明的變遷，有著緊密而複雜的關係。曾有病理學家宣稱：『人 類的歷史即其疾病的歷史』，或許有些誇張，但若不研究疾病的歷史，對人類社會恐怕無法有完整而 真確的認識。」 根據上文，下列選項何者最符合文意？', '["人類的疾病永遠無法根除，只能不斷尋求共存之道", "疾病是普世性的課題，必須加入歷史學的經驗累積", "除了病症本身，人類與疾病的各種互動也值得探究", "人類文明的發展與變遷，在於能夠更有效對抗疾病"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00132', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「塑膠危害已從海洋擴散至高山，根據水源樣本檢測，嘉明湖微塑膠平均檢出率為百分百，推估附近 臺灣水鹿每天透過湖水攝入80顆塑膠微粒，城市生產及使用的塑膠會隨排水系統進入環境、污染水 源，或裂解成更小的碎片或微粒，隨雨水和空氣進入動物棲地。微塑膠容易吸附環境及水中有毒物質， 若累積在體內的濃度增加，可能加重保育類動物的生存風險。」 根據上文，下列選項敘述何者正確？', '["塑膠微粒是從高山流向海洋而造成環境污染", "塑膠微粒並非透過人為的方式擴散影響範圍", "可以將減少塑膠危害列入保育動物的方法之一", "嘉明湖受到污染是因為遊客人數超出環境負荷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00133', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「因地球暖化，對比30年前的北極，我們會發現北極的冰快速融化。全球的水資源正一天天的流失， 我們必須快快改善用水習慣，避免浪費。我們要思考如何做好水資源管理，如何做好硬體（水庫建造 規劃）、軟體（教育宣導國人的用水習慣）來管理。如果我們把水庫當作是一部硬體，那輸入的軟體 就是國人的優良用水習慣和環保意識。」 根據上文，下列選項何者不符合文意？', '["關於水資源管理，政府單位應負責水庫建置規劃", "因應水資源的日漸流失，我們應該要做好水資源管理", "關於水資源管理，應教育人民有優良的用水習慣和環保意識", "科技進步所產生的污染，不斷地對地球上的水資源產生不利的影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00134', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「自駕車最終極的應用，將會是自動駕駛計程車跟分享式自駕車，未來的你早上上班，攔一輛自動駕 駛計程車，你可以在車上邊看電腦簡報、邊刮鬍子，不會有司機從後照鏡看你在幹嘛。到公司後，自 動駕駛計程車可以再去載其他人，當然，外面所有的停車場都可以改建成公園。」 根據上文，下列選項何者最符合文意？', '["科技帶動環境的改造，減少空氣的污染", "科技使人類減少互動，造成人際的疏離", "科技改變人類的生活，提供更多生活的便利", "科技始終來自於人性，人類才是科技的主宰者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00135', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '行政院對總統府發出的公文，最正確的「經辦語」是：', '["業經", "遵經", "嗣經", "爰經"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
